import anthropic, json, re

client = anthropic.Anthropic()

SEARCH_TOOL = {
    "name": "web_search",
    "description": "Search the web for current information",
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {"type": "string"},
            "max_results": {"type": "integer", "default": 5},
        },
        "required": ["query"],
    },
}

def build_prompt_with_citation_instruction(user_question: str) -> list[dict]:
    return [
        {
            "role": "user",
            "content": (
                f"{user_question}\n\n"
                "When you use information from a search result, cite it with a "
                "superscript marker like [1], [2], etc. List the sources at the "
                "end under a Sources heading."
            ),
        }
    ]

def extract_sources_from_tool_results(tool_results: list[dict]) -> list[dict]:
    """Map citation indices to source URLs from tool call outputs."""
    sources = []
    for result in tool_results:
        output = result.get("output", {})
        if isinstance(output, dict) and "results" in output:
            for item in output["results"]:
                if "url" in item and "title" in item:
                    sources.append({"url": item["url"], "title": item["title"]})
    return sources

# The model is instructed to use [1]-style markers; the client renders them as links

function renderWithCitations(text, sources) {
  // Replace [N] markers with clickable superscript links
  const cited = text.replace(/\[(\d+)\]/g, (match, n) => {
    const idx = parseInt(n) - 1;
    const source = sources[idx];
    if (!source) return match;
    return `<a href="${source.url}" target="_blank" rel="noopener" class="citation">[${n}]</a>`;
  });

  // Append sources section
  const sourceList = sources
    .map((s, i) =>
      `<li><a href="${s.url}" target="_blank" rel="noopener">[${i + 1}] ${s.title}</a></li>`
    )
    .join("");

  return `
    <div class="response-text">${marked.parse(cited)}</div>
    ${sourceList ? `<div class="sources"><h4>Sources</h4><ol>${sourceList}</ol></div>` : ""}
  `;
}

import anthropic, json

CONFIDENCE_TOOL = {
    "name": "rate_confidence",
    "description": "Rate your confidence in your answer based on the evidence quality",
    "input_schema": {
        "type": "object",
        "properties": {
            "level": {
                "type": "string",
                "enum": ["high", "medium", "low"],
                "description": (
                    "high: multiple consistent, authoritative sources. "
                    "medium: one source or partially verified. "
                    "low: uncertain, conflicting sources, or inference."
                ),
            },
            "reason": {"type": "string", "description": "One sentence explaining the confidence level"},
        },
        "required": ["level", "reason"],
    },
}

def ask_with_confidence(question: str, context: str) -> dict:
    """
    Ask the model to answer and simultaneously rate its confidence.
    Force-calls rate_confidence so we always get a structured rating.
    """
    client = anthropic.Anthropic()
    messages = [
        {"role": "user", "content": f"Context:\n{context}\n\nQuestion: {question}"},
    ]
    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=1024,
        tools=[CONFIDENCE_TOOL],
        messages=messages,
    )

    answer_text = ""
    confidence = {"level": "medium", "reason": ""}

    for block in response.content:
        if block.type == "text":
            answer_text = block.text
        elif block.type == "tool_use" and block.name == "rate_confidence":
            confidence = block.input

    return {"answer": answer_text, "confidence": confidence}

function ConfidenceBadge({ level, reason }) {
  const config = {
    high:   { label: "High confidence", color: "#22c55e", bg: "#052e16" },
    medium: { label: "Medium confidence", color: "#f59e0b", bg: "#451a03" },
    low:    { label: "Low confidence", color: "#ef4444", bg: "#450a0a" },
  }[level] || { label: "Unknown", color: "#94a3b8", bg: "#1e293b" };

  return `
    <span class="confidence-badge"
          style="color:${config.color};background:${config.bg}"
          title="${reason}">
      ${config.label}
    </span>
  `;
}

import anthropic, json

client = anthropic.Anthropic()

def answer_with_visible_reasoning(question: str) -> dict:
    """Return the answer and the full thinking trace."""
    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=16_000,
        thinking={"type": "enabled", "budget_tokens": 8_000},
        messages=[{"role": "user", "content": question}],
    )

    thinking_text = ""
    answer_text = ""

    for block in response.content:
        if block.type == "thinking":
            thinking_text = block.thinking
        elif block.type == "text":
            answer_text = block.text

    return {
        "answer": answer_text,
        "thinking": thinking_text,
        "usage": {
            "input_tokens": response.usage.input_tokens,
            "output_tokens": response.usage.output_tokens,
        },
    }

function renderThinkingDisclosure(thinking) {
  if (!thinking) return "";
  return `
    <details class="thinking-trace">
      <summary>Show reasoning (${Math.round(thinking.length / 4)} words)</summary>
      <pre class="thinking-content">${escapeHtml(thinking)}</pre>
    </details>
  `;
}

REASONING_TOOL = {
    "name": "structured_answer",
    "description": "Provide a structured answer with explicit reasoning steps",
    "input_schema": {
        "type": "object",
        "properties": {
            "steps": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "step": {"type": "integer"},
                        "description": {"type": "string"},
                        "finding": {"type": "string"},
                    },
                    "required": ["step", "description", "finding"],
                },
                "description": "Numbered reasoning steps, each with what you examined and what you found",
            },
            "conclusion": {"type": "string", "description": "Final answer based on the steps above"},
            "confidence": {
                "type": "string",
                "enum": ["high", "medium", "low"],
            },
            "caveats": {
                "type": "array",
                "items": {"type": "string"},
                "description": "Any limitations, assumptions, or edge cases the user should know",
            },
        },
        "required": ["steps", "conclusion", "confidence"],
    },
}

import anthropic

def reason_structurally(question: str, context: str) -> dict:
    client = anthropic.Anthropic()
    response = client.messages.create(
        model="claude-sonnet-5",
        max_tokens=2048,
        tools=[REASONING_TOOL],
        tool_choice={"type": "tool", "name": "structured_answer"},
        messages=[
            {
                "role": "user",
                "content": f"Context:\n{context}\n\nQuestion: {question}",
            }
        ],
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "structured_answer":
            return block.input
    return {}

